import os

def list_dir(path, indent=0):
    prefix = '  ' * indent
    if os.path.isdir(path):
        print(f'{prefix}{os.path.basename(path)}/')
        for item in os.listdir(path):
            list_dir(os.path.join(path, item), indent + 1)
    else:
        print(f'{prefix}{os.path.basename(path)}')

list_dir('target_project/old_backups')
